  if (state.registered) return;
  state.registered = true;

  function isPlainObject(value) {
    return Boolean(value) && typeof value === "object" && !Array.isArray(value);
  }

  function textIncludesScenario(text) {
    if (typeof text !== "string") return null;
    return SCENARIOS.find((scenario) => text.includes(scenario.anchor)) || null;
  }

  function valueScenario(value, depth = 0, seen = new Set()) {
    if (depth > 4 || value === undefined || value === null) return null;
    const direct = textIncludesScenario(value);
    if (direct) return direct;
    if (typeof value !== "object") return null;
    if (seen.has(value)) return null;
    seen.add(value);
    if (Array.isArray(value)) {
      for (const item of value) {
        const found = valueScenario(item, depth + 1, seen);
        if (found) return found;
      }
      return null;
    }
    for (const key of ["output", "message", "mes", "content", "text", "swipe", "swipes", "data", "detail"]) {
      const found = valueScenario(value[key], depth + 1, seen);
      if (found) return found;
    }
    return null;
  }

  function messageText(message) {
    if (!message || typeof message !== "object") return "";
    return [message.message, message.mes, message.content, message.text, message.output]
      .filter((value) => typeof value === "string")
      .join("\\n");
  }

  function activeMessageScenario(message) {
    const direct = valueScenario(message);
    if (direct) return direct;
    if (!isPlainObject(message)) return null;
    const swipes = Array.isArray(message.swipes) ? message.swipes : [];
    if (!swipes.length) return null;
    const rawIndex = message.swipe_id ?? message.swipeId ?? message.swipe_index ?? message.swipeIndex ?? message.current_swipe ?? message.currentSwipe;
